INSERT INTO `fqsi_yith_wcas_data_index_lookup` (`post_id`, `name`, `description`, `summary`, `url`, `sku`, `thumbnail`, `min_price`, `max_price`, `onsale`, `instock`, `stock_quantity`, `is_purchasable`, `rating_count`, `average_rating`, `total_sales`, `post_type`, `post_parent`, `product_type`, `parent_category`, `tags`, `lang`, `featured`, `custom_fields`, `custom_taxonomies`, `boost`) VALUES (13,'Wishlist','<!-- wp:shortcode -->[yith_wcwl_wishlist]<!-- /wp:shortcode -->','','https://antiviruspoint.org/wishlist-2/','','<img src=\"https://antiviruspoint.org/wp-content/themes/filson/images/default-thumbnail.jpg\" width=\"640px\" height=\"384px\" class=\"image-size-name\" />',0.0000,0.0000,0,0,0,0,0,0,0,'page',0,'','','','en_US',0,'','',0.00);
INSERT INTO `fqsi_yith_wcas_data_index_lookup` (`post_id`, `name`, `description`, `summary`, `url`, `sku`, `thumbnail`, `min_price`, `max_price`, `onsale`, `instock`, `stock_quantity`, `is_purchasable`, `rating_count`, `average_rating`, `total_sales`, `post_type`, `post_parent`, `product_type`, `parent_category`, `tags`, `lang`, `featured`, `custom_fields`, `custom_taxonomies`, `boost`) VALUES (14,'Refund and Returns Policy','<!-- wp:paragraph -->\r\n<p><b>This is a sample page.</b></p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h2 class=\"wp-block-heading\">Overview</h2>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Our refund and returns policy lasts 30 days. If 30 days have passed since your purchase, we canï¿½t offer you a full refund or exchange.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>To be eligible for a return, your item must be unused and in the same condition that you received it. It must also be in the original packaging.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Several types of goods are exempt from being returned. Perishable goods such as food, flowers, newspapers or magazines cannot be returned. We also do not accept products that are intimate or sanitary goods, hazardous materials, or flammable liquids or gases.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Additional non-returnable items:</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:list -->\r\n<ul>\r\n<li>Gift cards</li>\r\n<li>Downloadable software products</li>\r\n<li>Some health and personal care items</li>\r\n</ul>\r\n<!-- /wp:list -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>To complete your return, we require a receipt or proof of purchase.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Please do not send your purchase back to the manufacturer.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>There are certain situations where only partial refunds are granted:</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:list -->\r\n<ul>\r\n<li>Book with obvious signs of use</li>\r\n<li>CD, DVD, VHS tape, software, video game, cassette tape, or vinyl record that has been opened.</li>\r\n<li>Any item not in its original condition, is damaged or missing parts for reasons not due to our error.</li>\r\n<li>Any item that is returned more than 30 days after delivery</li>\r\n</ul>\r\n<!-- /wp:list -->\r\n\r\n<!-- wp:heading -->\r\n<h2 class=\"wp-block-heading\">Refunds</h2>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Once your return is received and inspected, we will send you an email to notify you that we have received your returned item. We will also notify you of the approval or rejection of your refund.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>If you are approved, then your refund will be processed, and a credit will automatically be applied to your credit card or original method of payment, within a certain amount of days.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h3 class=\"wp-block-heading\">Late or missing refunds</h3>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>If you havenï¿½t received a refund yet, first check your bank account again.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Then contact your credit card company, it may take some time before your refund is officially posted.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Next contact your bank. There is often some processing time before a refund is posted.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>If youï¿½ve done all of this and you still have not received your refund yet, please contact us at {email address}.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h3 class=\"wp-block-heading\">Sale items</h3>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Only regular priced items may be refunded. Sale items cannot be refunded.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h2 class=\"wp-block-heading\">Exchanges</h2>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>We only replace items if they are defective or damaged. If you need to exchange it for the same item, send us an email at {email address} and send your item to: {physical address}.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h2 class=\"wp-block-heading\">Gifts</h2>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>If the item was marked as a gift when purchased and shipped directly to you, youï¿½ll receive a gift credit for the value of your return. Once the returned item is received, a gift certificate will be mailed to you.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>If the item wasnï¿½t marked as a gift when purchased, or the gift giver had the order shipped to themselves to give to you later, we will send a refund to the gift giver and they will find out about your return.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h2 class=\"wp-block-heading\">Shipping returns</h2>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>To return your product, you should mail your product to: {physical address}.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>You will be responsible for paying for your own shipping costs for returning your item. Shipping costs are non-refundable. If you receive a refund, the cost of return shipping will be deducted from your refund.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Depending on where you live, the time it may take for your exchanged product to reach you may vary.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>If you are returning more expensive items, you may consider using a trackable shipping service or purchasing shipping insurance. We donï¿½t guarantee that we will receive your returned item.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h2 class=\"wp-block-heading\">Need help?</h2>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Contact us at {email} for questions related to refunds and returns.</p>\r\n<!-- /wp:paragraph -->','','https://antiviruspoint.org/shop/refund_returns/','','<img src=\"https://antiviruspoint.org/wp-content/themes/filson/images/default-thumbnail.jpg\" width=\"640px\" height=\"384px\" class=\"image-size-name\" />',0.0000,0.0000,0,0,0,0,0,0,0,'page',300553,'','','','en_US',0,'','',0.00);
