INSERT INTO `fqsi_yith_wcas_data_index_lookup` (`post_id`, `name`, `description`, `summary`, `url`, `sku`, `thumbnail`, `min_price`, `max_price`, `onsale`, `instock`, `stock_quantity`, `is_purchasable`, `rating_count`, `average_rating`, `total_sales`, `post_type`, `post_parent`, `product_type`, `parent_category`, `tags`, `lang`, `featured`, `custom_fields`, `custom_taxonomies`, `boost`) VALUES (300654,'FAQs','<h2>Frequently Asked Questions</h2>					<p>This Agreement was last modified on 21st January 2025\n</p>							\n					<h4 id=\"elementor-tab-title-2761\" data-tab=\"1\" role=\"button\" aria-controls=\"elementor-tab-content-2761\" aria-expanded=\"false\">\n															<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H272V64c0-17.67-14.33-32-32-32h-32c-17.67 0-32 14.33-32 32v144H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h144v144c0 17.67 14.33 32 32 32h32c17.67 0 32-14.33 32-32V304h144c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n								<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h384c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n												<a tabindex=\"0\"> Can I return the software back after purchase?</a>\n					</h4>\n					<p>No. Returning software after purchase does not follow our company profile. We do not support any return policy.</p>\n					<h4 id=\"elementor-tab-title-2762\" data-tab=\"2\" role=\"button\" aria-controls=\"elementor-tab-content-2762\" aria-expanded=\"false\">\n															<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H272V64c0-17.67-14.33-32-32-32h-32c-17.67 0-32 14.33-32 32v144H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h144v144c0 17.67 14.33 32 32 32h32c17.67 0 32-14.33 32-32V304h144c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n								<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h384c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n												<a tabindex=\"0\"> Do you offer hardware products and if yes, what are the shipping methods?</a>\n					</h4>\n					<p>All our products are software-based. You can download your software through our portal after the purchase process is completed.</p>\n					<h4 id=\"elementor-tab-title-2763\" data-tab=\"3\" role=\"button\" aria-controls=\"elementor-tab-content-2763\" aria-expanded=\"false\">\n															<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H272V64c0-17.67-14.33-32-32-32h-32c-17.67 0-32 14.33-32 32v144H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h144v144c0 17.67 14.33 32 32 32h32c17.67 0 32-14.33 32-32V304h144c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n								<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h384c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n												<a tabindex=\"0\">How Do I Place an Order?</a>\n					</h4>\n					<p>You can place your order from our website after registering. Browse the product you need, add it to your cart, and then proceed to checkout and you are all set to go.</p>\n					<h4 id=\"elementor-tab-title-2764\" data-tab=\"4\" role=\"button\" aria-controls=\"elementor-tab-content-2764\" aria-expanded=\"false\">\n															<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H272V64c0-17.67-14.33-32-32-32h-32c-17.67 0-32 14.33-32 32v144H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h144v144c0 17.67 14.33 32 32 32h32c17.67 0 32-14.33 32-32V304h144c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n								<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h384c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n												<a tabindex=\"0\">Is it compulsory to have an account for placing orders?</a>\n					</h4>\n					<p>Yes, you would need to make an account to place an order.</p>\n					<h4 id=\"elementor-tab-title-2765\" data-tab=\"5\" role=\"button\" aria-controls=\"elementor-tab-content-2765\" aria-expanded=\"false\">\n															<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H272V64c0-17.67-14.33-32-32-32h-32c-17.67 0-32 14.33-32 32v144H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h144v144c0 17.67 14.33 32 32 32h32c17.67 0 32-14.33 32-32V304h144c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n								<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h384c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n												<a tabindex=\"0\">How often do I need to update my antivirus software?</a>\n					</h4>\n					<p>Our antivirus software automatically detects new updates and will inform you about them. You can also simply grant permission for automatic updates while setting up the software.</p>','','https://antiviruspoint.org/shop/faqs/','','<img src=\"https://antiviruspoint.org/wp-content/themes/filson/images/default-thumbnail.jpg\" width=\"640px\" height=\"384px\" class=\"image-size-name\" />',0.0000,0.0000,0,0,0,0,0,0,0,'page',300553,'','','','en_US',0,'','',0.00);
INSERT INTO `fqsi_yith_wcas_data_index_lookup` (`post_id`, `name`, `description`, `summary`, `url`, `sku`, `thumbnail`, `min_price`, `max_price`, `onsale`, `instock`, `stock_quantity`, `is_purchasable`, `rating_count`, `average_rating`, `total_sales`, `post_type`, `post_parent`, `product_type`, `parent_category`, `tags`, `lang`, `featured`, `custom_fields`, `custom_taxonomies`, `boost`) VALUES (90006987,'Norton 360 Standard - 1-Year / 1-Device - USA/Canada','This is a one year pre-paid subcription of Norton 360 Standard for 1 device.\r\n\r\nRenews Automatically each year. (Enrollment with Norton is required but can be cancelled at any time)\r\n\r\nEnrollment - Credit/Debit Card or PayPal required for activation (Auto-renewal direct with Norton) and can be switched off at any time after the product is activated.\r\n\r\nNorton 360 Standard includes:\r\n\r\n- Real-time Threat Protection\r\n- Secure VPN\r\n- Smart Firewall\r\n- Password Manager\r\n- 10 GB Cloud Backup\r\n- SafeCam','Brand: Symantec / Norton\r\nMedia Type: Download\r\nPlatform: Windows 7, Windows 8, Windows 10, Windows 11, Mac OS (Current and previous two versions), Android 8 or later, iOS (Current and previous two versions)','https://antiviruspoint.org/product/norton-360-standard-1-year-1-device-usa-canada/','SKU-001','a:2:{s:5:\"small\";s:117:\"https://antiviruspoint.org/wp-content/uploads/2025/01/Norton-360-Deluxe-Subscription-5-Devices-500x500-2-150x150.webp\";s:3:\"big\";s:117:\"https://antiviruspoint.org/wp-content/uploads/2025/01/Norton-360-Deluxe-Subscription-5-Devices-500x500-2-300x300.webp\";}',43.5000,90.0000,1,1,9,1,0,0,3,'product',0,'simple','a:4:{i:0;i:59;i:1;i:64;i:2;i:60;i:3;i:68;}','a:3:{i:0;i:69;i:1;i:70;i:2;i:71;}','en_US',0,'','a:0:{}',0.00);
INSERT INTO `fqsi_yith_wcas_data_index_lookup` (`post_id`, `name`, `description`, `summary`, `url`, `sku`, `thumbnail`, `min_price`, `max_price`, `onsale`, `instock`, `stock_quantity`, `is_purchasable`, `rating_count`, `average_rating`, `total_sales`, `post_type`, `post_parent`, `product_type`, `parent_category`, `tags`, `lang`, `featured`, `custom_fields`, `custom_taxonomies`, `boost`) VALUES (90006989,'Norton 360 Deluxe with LifeLock Select - 1-Year / 5-Device','Norton 360 with LifeLock Select\nProtection from viruses, hackers, and identity thieves. A VPN to help keep your internet browsing private, plus parental control.\n\nAll-in-one protection for your devices, online privacy, and identity\n\nNorton 360 with LifeLock Select gives you comprehensive malware protection for up to 5 PC, Macï¿½, Androidï¿½ or iOS devices, including 100GB of secure Cloud Backup and Secure VPN for all 5 devices.\n\nAlso included are features such as Parental Control to help protect your children online, and Dark Web Monitoring, where we monitor and notify you if we find your personal information on the dark web.\n\nLifeLock identity theft protection includes Stolen Wallet protection, Credit Monitoring and the LifeLock Identity Alertï¿½ System. Plus, get up to $25k in Stolen Funds Reimbursement and up to $1 million in Coverage for Lawyers and Experts if needed to help restore your identity.','Brand: Symantec\r\nMedia Type: Download\r\nPlatform: Windows 7, Windows 8, Windows 10, Windows 11, Mac OS (Current and previous two versions), Android 8 or later, iOS (Current and previous two versions)','https://antiviruspoint.org/product/norton-360-deluxe-with-lifelock-select-1-year-5-device/','SKU-002','a:2:{s:5:\"small\";s:142:\"https://i0.wp.com/antiviruspoint.org/wp-content/uploads/2025/01/Norton-360-Premium-10-devices-500x500-1.webp?resize=150%2C150&quality=80&ssl=1\";s:3:\"big\";s:142:\"https://i0.wp.com/antiviruspoint.org/wp-content/uploads/2025/01/Norton-360-Premium-10-devices-500x500-1.webp?resize=300%2C300&quality=80&ssl=1\";}',200.0000,210.0000,1,1,9,1,0,0,0,'product',0,'simple','a:6:{i:0;i:59;i:1;i:64;i:2;i:60;i:3;i:61;i:4;i:62;i:5;i:63;}','a:6:{i:0;i:77;i:1;i:100;i:2;i:96;i:3;i:74;i:4;i:103;i:5;i:75;}','en_US',0,'','a:0:{}',0.00);
INSERT INTO `fqsi_yith_wcas_data_index_lookup` (`post_id`, `name`, `description`, `summary`, `url`, `sku`, `thumbnail`, `min_price`, `max_price`, `onsale`, `instock`, `stock_quantity`, `is_purchasable`, `rating_count`, `average_rating`, `total_sales`, `post_type`, `post_parent`, `product_type`, `parent_category`, `tags`, `lang`, `featured`, `custom_fields`, `custom_taxonomies`, `boost`) VALUES (90006992,'Norton Secure VPN - 1-Year / 5-Device','Norton Secure VPN\r\nSecure private information like your passwords, bank details and credit card numbers when using public Wi-Fi on your PC, Mac or mobile device.\r\n\r\nWhy use Norton Secure VPN?\r\nSome VPN companies can see all the websites you visit. Choosing a brand\r\nyou can trust is paramount.\r\n\r\nNorton Secure VPN gives you:\r\n\r\nOnline privacy\r\nHelps protect your online privacy by shielding your internet data and your location from advertisers, websites and cybercriminals.\r\nCan block ad tracking technologies to avoid being tracked online by advertisers and other companies, helping to eliminate many of the targeted ads that follow you around the web.\r\nContent access\r\nCan enable global access to your favorite apps and websites while on the go, just like home.\r\nWi-Fi security\r\nLets you check email, interact on social media and pay bills using public Wi-Fi hotspots without worrying about cybercriminals intercepting the information you send and receive on a shared network.\r\nPrivacy &amp; security\r\nUses bank-grade encryption to help ensure the information you send and receive is secure and private.','Brand: Symantec\r\nMedia Type: Download\r\nPlatform: Windows 7, Windows 8, Windows 10, Windows 11, Mac OS (Current and previous two versions), Android 8 or later, iOS (Current and previous two versions)','https://antiviruspoint.org/product/norton-secure-vpn-1-year-5-device/','SKU-003','a:2:{s:5:\"small\";s:107:\"https://antiviruspoint.org/wp-content/uploads/2025/01/Norton-Secure-VPN-1-yr-Generic-500x500-2-150x150.webp\";s:3:\"big\";s:107:\"https://antiviruspoint.org/wp-content/uploads/2025/01/Norton-Secure-VPN-1-yr-Generic-500x500-2-300x300.webp\";}',43.0000,45.0000,1,0,0,1,1,1,0,'product',0,'simple','a:6:{i:0;i:15;i:1;i:59;i:2;i:61;i:3;i:62;i:4;i:63;i:5;i:68;}','a:4:{i:0;i:77;i:1;i:103;i:2;i:75;i:3;i:73;}','en_US',0,'','a:0:{}',0.00);
