ownload\r\nPlatform: Windows 8, Windows 10, Windows 11, Mac OS 10.12, Mac OS 10.13, Mac OS 10.14, Mac OS 10.15, Mac OS 11, Mac OS 12, Android 7, Android 8, Android 9, Android 10, Android 11, Android 12, iOS 13, iOS 14, iOS 15','https://antiviruspoint.org/?post_type=product&p=90006993','SKU-004','a:2:{s:5:\"small\";s:106:\"https://antiviruspoint.org/wp-content/uploads/2025/01/McAfee-Internet-Security-2018-500x500-2-150x150.webp\";s:3:\"big\";s:106:\"https://antiviruspoint.org/wp-content/uploads/2025/01/McAfee-Internet-Security-2018-500x500-2-300x300.webp\";}',18.0000,18.0000,0,0,0,1,0,0,0,'product',0,'simple','a:4:{i:0;i:59;i:1;i:64;i:2;i:60;i:3;i:68;}','a:9:{i:0;i:77;i:1;i:100;i:2;i:96;i:3;i:74;i:4;i:76;i:5;i:80;i:6;i:93;i:7;i:81;i:8;i:95;}','en_US',0,'','a:0:{}',0.00);
