INSERT INTO `fqsi_yith_wcas_data_index_lookup` (`post_id`, `name`, `description`, `summary`, `url`, `sku`, `thumbnail`, `min_price`, `max_price`, `onsale`, `instock`, `stock_quantity`, `is_purchasable`, `rating_count`, `average_rating`, `total_sales`, `post_type`, `post_parent`, `product_type`, `parent_category`, `tags`, `lang`, `featured`, `custom_fields`, `custom_taxonomies`, `boost`) VALUES (90006997,'McAfee Total Protection - 1-Year / 3-Devices','Powerful PC Protection\r\n\r\nStay safe from Trojans, viruses, spyware, rootkits, and more, with state-of-the-art anti-malware protection\r\nStop worrying about performance hitsï¿½the advanced scanning engine checks for threats quickly without compromising battery performance\r\nKeep zero-day threats and botnets at bayï¿½McAfee ActiveProtectionï¿½ and NetGuardï¿½ technology have you covered\r\n\r\nFolder and File Encryption\r\n\r\nSecure your identity and data by locking your confidential files in a password-protected vault\r\n\r\nSocial Network Protection\r\n\r\nCreate brief, trustworthy URLs with a Safe URL Shortener and spread the news, not spam or malware\r\n\r\nWireless Network Protection\r\n\r\nKeep eavesdroppers away from your passwords and personal files when connected to open wireless networks\r\n\r\nPrivacy and PC Optimization Tools\r\n\r\nFind and patch holes in Windows and applications with McAfee Vulnerability Scanner\r\nEnhance your PC\'s performance by deleting unnecessary files with McAfee QuickCleanï¿½\r\nSecurely destroy sensitive files, such as tax documents, with McAfee Shredderï¿½\r\n\r\nAdditional Features\r\n\r\nEffective Parental Controls\r\n\r\nBlock inappropriate sites and set time limits for Internet use\r\nCheck user login times, attempts to access forbidden sites, and total time spent online\r\nSee what your kids have been up to online with a detailed usage report\r\n\r\nSpam and Dangerous Email Filter\r\n\r\nMake sure dangerous and annoying emails never make it into your inbox with McAfee\'s most accurate filter yet\r\n\r\nTwo-Way Firewall\r\n\r\nShut out hackers and prevent malicious software from exploiting your OS or stealing your information\r\n\r\nNetwork Intrusion Security\r\n\r\nFind out if someone is stealing your Internet connectionï¿½My Home Network shows you all your connected devices\r\n\r\nAdvanced Web Protection\r\n\r\nKnow if a site you\'re about to visit is dangerous with McAfee SiteAdvisorï¿½ï¿½just look for the red, yellow, and green safety ratings\r\nStay protected from phishing URLs in email and instant messages with the SiteAdvisorï¿½ LIVE add-on','Brand: McAfee\r\nMedia Type: Download\r\nPlatform: Windows 8, Windows 10, Windows 11, Mac OS 10.12, Mac OS 10.13, Mac OS 10.14, Mac OS 10.15, Mac OS 11, Mac OS 12, Android 7, Android 8, Android 9, Android 10, Android 11, Android 12, iOS 13, iOS 14, iOS 15','https://antiviruspoint.org/product/mcafee-total-protection-1-year-3-devices-2/','SKU-006','a:2:{s:5:\"small\";s:141:\"https://i0.wp.com/antiviruspoint.org/wp-content/uploads/2025/01/McAfee-Total-Protection-2018-500x500-2.webp?resize=150%2C150&quality=80&ssl=1\";s:3:\"big\";s:141:\"https://i0.wp.com/antiviruspoint.org/wp-content/uploads/2025/01/McAfee-Total-Protection-2018-500x500-2.webp?resize=300%2C300&quality=80&ssl=1\";}',40.0000,100.0000,1,0,0,1,0,0,1,'product',0,'simple','a:5:{i:0;i:59;i:1;i:60;i:2;i:61;i:3;i:62;i:4;i:68;}','a:4:{i:0;i:77;i:1;i:100;i:2;i:96;i:3;i:103;}','en_US',0,'','a:0:{}',0.00);
